mapper.delete:
DELETE FROM AR_MAC_RECORDS_TEMP
 WHERE UPLOAD_BY = #{adminID, jdbcType=VARCHAR}
   AND CPNY_ID   = #{cpnyId,  jdbcType=VARCHAR}

mapper.select:
SELECT LINE_ID, CARD_NO, R_TIME, DOOR_TYPE, EMPID, REMARK,
       LOCAL_NAME, R_DATE, AR_DATE_STR, UPLOAD_ERROR_MSG, RESULT_FLAG
  FROM AR_MAC_RECORDS_TEMP
 WHERE UPLOAD_BY = #{adminID, jdbcType=VARCHAR}
   AND CPNY_ID   = #{cpnyId,  jdbcType=VARCHAR}
 ORDER BY LINE_ID

SELECT COUNT(*)
  FROM AR_MAC_RECORDS_HTSV
 WHERE CARD_NO   = #{cardNo,           jdbcType=VARCHAR}
   AND R_TIME    = TO_DATE(#{combinedDatetime, jdbcType=VARCHAR}, 'YYYY/MM/DD HH24:MI')
   AND DOOR_TYPE = #{doorType,         jdbcType=VARCHAR}
   AND ACTIVITY  = 1
